contract WaultSwapRouter is IWaultSwapRouter02 {

    using SafeMath for uint;



    address public immutable override factory;

    address public immutable override WETH;



    modifier ensure(uint deadline) {

        require(deadline >= block.timestamp, 'WaultSwapRouter: EXPIRED');

        _;

    }



    constructor(address _factory, address _WETH) public {

        factory = _factory;

        WETH = _WETH;

    }



    receive() external payable {

        assert(msg.sender == WETH); 

    }





    function _addLiquidity(

        address tokenA,

        address tokenB,

        uint amountADesired,

        uint amountBDesired,

        uint amountAMin,

        uint amountBMin

    ) internal virtual returns (uint amountA, uint amountB) {



        if (IWaultSwapFactory(factory).getPair(tokenA, tokenB) == address(0)) {

            IWaultSwapFactory(factory).createPair(tokenA, tokenB);

        }

        (uint reserveA, uint reserveB) = WaultSwapLibrary.getReserves(factory, tokenA, tokenB);

        if (reserveA == 0 && reserveB == 0) {

            (amountA, amountB) = (amountADesired, amountBDesired);

        } else {

            uint amountBOptimal = WaultSwapLibrary.quote(amountADesired, reserveA, reserveB);

            if (amountBOptimal <= amountBDesired) {

                require(amountBOptimal >= amountBMin, 'WaultSwapRouter: INSUFFICIENT_B_AMOUNT');

                (amountA, amountB) = (amountADesired, amountBOptimal);

            } else {

                uint amountAOptimal = WaultSwapLibrary.quote(amountBDesired, reserveB, reserveA);

                assert(amountAOptimal <= amountADesired);

                require(amountAOptimal >= amountAMin, 'WaultSwapRouter: INSUFFICIENT_A_AMOUNT');

                (amountA, amountB) = (amountAOptimal, amountBDesired);

            }

        }

    }

    function addLiquidity(

        address tokenA,

        address tokenB,

        uint amountADesired,

        uint amountBDesired,

        uint amountAMin,

        uint amountBMin,

        address to,

        uint deadline

    ) external virtual override ensure(deadline) returns (uint amountA, uint amountB, uint liquidity) {

        (amountA, amountB) = _addLiquidity(tokenA, tokenB, amountADesired, amountBDesired, amountAMin, amountBMin);

        address pair = WaultSwapLibrary.pairFor(factory, tokenA, tokenB);

        TransferHelper.safeTransferFrom(tokenA, msg.sender, pair, amountA);

        TransferHelper.safeTransferFrom(tokenB, msg.sender, pair, amountB);

        liquidity = IWaultSwapPair(pair).mint(to);

    }

    function addLiquidityETH(

        address token,

        uint amountTokenDesired,

        uint amountTokenMin,

        uint amountETHMin,

        address to,

        uint deadline

    ) external virtual override payable ensure(deadline) returns (uint amountToken, uint amountETH, uint liquidity) {

        (amountToken, amountETH) = _addLiquidity(

            token,

            WETH,

            amountTokenDesired,

            msg.value,

            amountTokenMin,

            amountETHMin

        );

        address pair = WaultSwapLibrary.pairFor(factory, token, WETH);

        TransferHelper.safeTransferFrom(token, msg.sender, pair, amountToken);

        IWETH(WETH).deposit{value: amountETH}();

        assert(IWETH(WETH).transfer(pair, amountETH));

        liquidity = IWaultSwapPair(pair).mint(to);



        if (msg.value > amountETH) TransferHelper.safeTransferETH(msg.sender, msg.value - amountETH);

    }





    function removeLiquidity(

        address tokenA,

        address tokenB,

        uint liquidity,

        uint amountAMin,

        uint amountBMin,

        address to,

        uint deadline

    ) public virtual override ensure(deadline) returns (uint amountA, uint amountB) {

        address pair = WaultSwapLibrary.pairFor(factory, tokenA, tokenB);

        IWaultSwapPair(pair).transferFrom(msg.sender, pair, liquidity); 

        (uint amount0, uint amount1) = IWaultSwapPair(pair).burn(to);

        (address token0,) = WaultSwapLibrary.sortTokens(tokenA, tokenB);

        (amountA, amountB) = tokenA == token0 ? (amount0, amount1) : (amount1, amount0);

        require(amountA >= amountAMin, 'WaultSwapRouter: INSUFFICIENT_A_AMOUNT');

        require(amountB >= amountBMin, 'WaultSwapRouter: INSUFFICIENT_B_AMOUNT');

    }

    function removeLiquidityETH(

        address token,

        uint liquidity,

        uint amountTokenMin,

        uint amountETHMin,

        address to,

        uint deadline

    ) public virtual override ensure(deadline) returns (uint amountToken, uint amountETH) {

        (amountToken, amountETH) = removeLiquidity(

            token,

            WETH,

            liquidity,

            amountTokenMin,

            amountETHMin,

            address(this),

            deadline

        );

        TransferHelper.safeTransfer(token, to, amountToken);

        IWETH(WETH).withdraw(amountETH);

        TransferHelper.safeTransferETH(to, amountETH);

    }

    function removeLiquidityWithPermit(

        address tokenA,

        address tokenB,

        uint liquidity,

        uint amountAMin,

        uint amountBMin,

        address to,

        uint deadline,

        bool approveMax, uint8 v, bytes32 r, bytes32 s

    ) external virtual override returns (uint amountA, uint amountB) {

        address pair = WaultSwapLibrary.pairFor(factory, tokenA, tokenB);

        uint value = approveMax ? uint(-1) : liquidity;

        IWaultSwapPair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);

        (amountA, amountB) = removeLiquidity(tokenA, tokenB, liquidity, amountAMin, amountBMin, to, deadline);

    }

    function removeLiquidityETHWithPermit(

        address token,

        uint liquidity,

        uint amountTokenMin,

        uint amountETHMin,

        address to,

        uint deadline,

        bool approveMax, uint8 v, bytes32 r, bytes32 s

    ) external virtual override returns (uint amountToken, uint amountETH) {

        address pair = WaultSwapLibrary.pairFor(factory, token, WETH);

        uint value = approveMax ? uint(-1) : liquidity;

        IWaultSwapPair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);

        (amountToken, amountETH) = removeLiquidityETH(token, liquidity, amountTokenMin, amountETHMin, to, deadline);

    }





    function removeLiquidityETHSupportingFeeOnTransferTokens(

        address token,

        uint liquidity,

        uint amountTokenMin,

        uint amountETHMin,

        address to,

        uint deadline

    ) public virtual override ensure(deadline) returns (uint amountETH) {

        (, amountETH) = removeLiquidity(

            token,

            WETH,

            liquidity,

            amountTokenMin,

            amountETHMin,

            address(this),

            deadline

        );

        TransferHelper.safeTransfer(token, to, IERC20(token).balanceOf(address(this)));

        IWETH(WETH).withdraw(amountETH);

        TransferHelper.safeTransferETH(to, amountETH);

    }

    function removeLiquidityETHWithPermitSupportingFeeOnTransferTokens(

        address token,

        uint liquidity,

        uint amountTokenMin,

        uint amountETHMin,

        address to,

        uint deadline,

        bool approveMax, uint8 v, bytes32 r, bytes32 s

    ) external virtual override returns (uint amountETH) {

        address pair = WaultSwapLibrary.pairFor(factory, token, WETH);

        uint value = approveMax ? uint(-1) : liquidity;

        IWaultSwapPair(pair).permit(msg.sender, address(this), value, deadline, v, r, s);

        amountETH = removeLiquidityETHSupportingFeeOnTransferTokens(

            token, liquidity, amountTokenMin, amountETHMin, to, deadline

        );

    }







    function _swap(uint[] memory amounts, address[] memory path, address _to) internal virtual {

        for (uint i; i < path.length - 1; i++) {

            (address input, address output) = (path[i], path[i + 1]);

            (address token0,) = WaultSwapLibrary.sortTokens(input, output);

            uint amountOut = amounts[i + 1];

            (uint amount0Out, uint amount1Out) = input == token0 ? (uint(0), amountOut) : (amountOut, uint(0));

            address to = i < path.length - 2 ? WaultSwapLibrary.pairFor(factory, output, path[i + 2]) : _to;

            IWaultSwapPair(WaultSwapLibrary.pairFor(factory, input, output)).swap(

                amount0Out, amount1Out, to, new bytes(0)

            );

        }

    }

    function swapExactTokensForTokens(

        uint amountIn,

        uint amountOutMin,

        address[] calldata path,

        address to,

        uint deadline

    ) external virtual override ensure(deadline) returns (uint[] memory amounts) {

        amounts = WaultSwapLibrary.getAmountsOut(factory, amountIn, path);

        require(amounts[amounts.length - 1] >= amountOutMin, 'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT');

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]

        );

        _swap(amounts, path, to);

    }

    function swapTokensForExactTokens(

        uint amountOut,

        uint amountInMax,

        address[] calldata path,

        address to,

        uint deadline

    ) external virtual override ensure(deadline) returns (uint[] memory amounts) {

        amounts = WaultSwapLibrary.getAmountsIn(factory, amountOut, path);

        require(amounts[0] <= amountInMax, 'WaultSwapRouter: EXCESSIVE_INPUT_AMOUNT');

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]

        );

        _swap(amounts, path, to);

    }

    function swapExactETHForTokens(uint amountOutMin, address[] calldata path, address to, uint deadline)

        external

        virtual

        override

        payable

        ensure(deadline)

        returns (uint[] memory amounts)

    {

        require(path[0] == WETH, 'WaultSwapRouter: INVALID_PATH');

        amounts = WaultSwapLibrary.getAmountsOut(factory, msg.value, path);

        require(amounts[amounts.length - 1] >= amountOutMin, 'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT');

        IWETH(WETH).deposit{value: amounts[0]}();

        assert(IWETH(WETH).transfer(WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]));

        _swap(amounts, path, to);

    }

    function swapTokensForExactETH(uint amountOut, uint amountInMax, address[] calldata path, address to, uint deadline)

        external

        virtual

        override

        ensure(deadline)

        returns (uint[] memory amounts)

    {

        require(path[path.length - 1] == WETH, 'WaultSwapRouter: INVALID_PATH');

        amounts = WaultSwapLibrary.getAmountsIn(factory, amountOut, path);

        require(amounts[0] <= amountInMax, 'WaultSwapRouter: EXCESSIVE_INPUT_AMOUNT');

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]

        );

        _swap(amounts, path, address(this));

        IWETH(WETH).withdraw(amounts[amounts.length - 1]);

        TransferHelper.safeTransferETH(to, amounts[amounts.length - 1]);

    }

    function swapExactTokensForETH(uint amountIn, uint amountOutMin, address[] calldata path, address to, uint deadline)

        external

        virtual

        override

        ensure(deadline)

        returns (uint[] memory amounts)

    {

        require(path[path.length - 1] == WETH, 'WaultSwapRouter: INVALID_PATH');

        amounts = WaultSwapLibrary.getAmountsOut(factory, amountIn, path);

        require(amounts[amounts.length - 1] >= amountOutMin, 'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT');

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]

        );

        _swap(amounts, path, address(this));

        IWETH(WETH).withdraw(amounts[amounts.length - 1]);

        TransferHelper.safeTransferETH(to, amounts[amounts.length - 1]);

    }

    function swapETHForExactTokens(uint amountOut, address[] calldata path, address to, uint deadline)

        external

        virtual

        override

        payable

        ensure(deadline)

        returns (uint[] memory amounts)

    {

        require(path[0] == WETH, 'WaultSwapRouter: INVALID_PATH');

        amounts = WaultSwapLibrary.getAmountsIn(factory, amountOut, path);

        require(amounts[0] <= msg.value, 'WaultSwapRouter: EXCESSIVE_INPUT_AMOUNT');

        IWETH(WETH).deposit{value: amounts[0]}();

        assert(IWETH(WETH).transfer(WaultSwapLibrary.pairFor(factory, path[0], path[1]), amounts[0]));

        _swap(amounts, path, to);



        if (msg.value > amounts[0]) TransferHelper.safeTransferETH(msg.sender, msg.value - amounts[0]);

    }







    function _swapSupportingFeeOnTransferTokens(address[] memory path, address _to) internal virtual {

        for (uint i; i < path.length - 1; i++) {

            (address input, address output) = (path[i], path[i + 1]);

            (address token0,) = WaultSwapLibrary.sortTokens(input, output);

            IWaultSwapPair pair = IWaultSwapPair(WaultSwapLibrary.pairFor(factory, input, output));

            uint amountInput;

            uint amountOutput;

            { 

            (uint reserve0, uint reserve1,) = pair.getReserves();

            (uint reserveInput, uint reserveOutput) = input == token0 ? (reserve0, reserve1) : (reserve1, reserve0);

            amountInput = IERC20(input).balanceOf(address(pair)).sub(reserveInput);

            amountOutput = WaultSwapLibrary.getAmountOut(amountInput, reserveInput, reserveOutput);

            }

            (uint amount0Out, uint amount1Out) = input == token0 ? (uint(0), amountOutput) : (amountOutput, uint(0));

            address to = i < path.length - 2 ? WaultSwapLibrary.pairFor(factory, output, path[i + 2]) : _to;

            pair.swap(amount0Out, amount1Out, to, new bytes(0));

        }

    }

    function swapExactTokensForTokensSupportingFeeOnTransferTokens(

        uint amountIn,

        uint amountOutMin,

        address[] calldata path,

        address to,

        uint deadline

    ) external virtual override ensure(deadline) {

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amountIn

        );

        uint balanceBefore = IERC20(path[path.length - 1]).balanceOf(to);

        _swapSupportingFeeOnTransferTokens(path, to);

        require(

            IERC20(path[path.length - 1]).balanceOf(to).sub(balanceBefore) >= amountOutMin,

            'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT'

        );

    }

    function swapExactETHForTokensSupportingFeeOnTransferTokens(

        uint amountOutMin,

        address[] calldata path,

        address to,

        uint deadline

    )

        external

        virtual

        override

        payable

        ensure(deadline)

    {

        require(path[0] == WETH, 'WaultSwapRouter: INVALID_PATH');

        uint amountIn = msg.value;

        IWETH(WETH).deposit{value: amountIn}();

        assert(IWETH(WETH).transfer(WaultSwapLibrary.pairFor(factory, path[0], path[1]), amountIn));

        uint balanceBefore = IERC20(path[path.length - 1]).balanceOf(to);

        _swapSupportingFeeOnTransferTokens(path, to);

        require(

            IERC20(path[path.length - 1]).balanceOf(to).sub(balanceBefore) >= amountOutMin,

            'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT'

        );

    }

    function swapExactTokensForETHSupportingFeeOnTransferTokens(

        uint amountIn,

        uint amountOutMin,

        address[] calldata path,

        address to,

        uint deadline

    )

        external

        virtual

        override

        ensure(deadline)

    {

        require(path[path.length - 1] == WETH, 'WaultSwapRouter: INVALID_PATH');

        TransferHelper.safeTransferFrom(

            path[0], msg.sender, WaultSwapLibrary.pairFor(factory, path[0], path[1]), amountIn

        );

        _swapSupportingFeeOnTransferTokens(path, address(this));

        uint amountOut = IERC20(WETH).balanceOf(address(this));

        require(amountOut >= amountOutMin, 'WaultSwapRouter: INSUFFICIENT_OUTPUT_AMOUNT');

        IWETH(WETH).withdraw(amountOut);

        TransferHelper.safeTransferETH(to, amountOut);

    }





    function quote(uint amountA, uint reserveA, uint reserveB) public pure virtual override returns (uint amountB) {

        return WaultSwapLibrary.quote(amountA, reserveA, reserveB);

    }



    function getAmountOut(uint amountIn, uint reserveIn, uint reserveOut)

        public

        pure

        virtual

        override

        returns (uint amountOut)

    {

        return WaultSwapLibrary.getAmountOut(amountIn, reserveIn, reserveOut);

    }



    function getAmountIn(uint amountOut, uint reserveIn, uint reserveOut)

        public

        pure

        virtual

        override

        returns (uint amountIn)

    {

        return WaultSwapLibrary.getAmountIn(amountOut, reserveIn, reserveOut);

    }



    function getAmountsOut(uint amountIn, address[] memory path)

        public

        view

        virtual

        override

        returns (uint[] memory amounts)

    {

        return WaultSwapLibrary.getAmountsOut(factory, amountIn, path);

    }



    function getAmountsIn(uint amountOut, address[] memory path)

        public

        view

        virtual

        override

        returns (uint[] memory amounts)

    {

        return WaultSwapLibrary.getAmountsIn(factory, amountOut, path);

    }

}

pragma solidity 0.8.9;


abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _setOwner(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount) external returns (bool);


    function allowance(address owner, address spender) external view returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(address indexed owner, address indexed spender, uint256 value);
}


library Address {

    function isContract(address account) internal view returns (bool) {




        uint256 size;
        assembly {
            size := extcodesize(account)
        }
        return size > 0;
    }


    function sendValue(address payable recipient, uint256 amount) internal {
        require(address(this).balance >= amount, "Address: insufficient balance");

        (bool success, ) = recipient.call{value: amount}("");
        require(success, "Address: unable to send value, recipient may have reverted");
    }


    function functionCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionCall(target, data, "Address: low-level call failed");
    }


    function functionCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, 0, errorMessage);
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value
    ) internal returns (bytes memory) {
        return functionCallWithValue(target, data, value, "Address: low-level call with value failed");
    }


    function functionCallWithValue(
        address target,
        bytes memory data,
        uint256 value,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(address(this).balance >= value, "Address: insufficient balance for call");
        require(isContract(target), "Address: call to non-contract");

        (bool success, bytes memory returndata) = target.call{value: value}(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionStaticCall(address target, bytes memory data) internal view returns (bytes memory) {
        return functionStaticCall(target, data, "Address: low-level static call failed");
    }


    function functionStaticCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal view returns (bytes memory) {
        require(isContract(target), "Address: static call to non-contract");

        (bool success, bytes memory returndata) = target.staticcall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }


    function functionDelegateCall(address target, bytes memory data) internal returns (bytes memory) {
        return functionDelegateCall(target, data, "Address: low-level delegate call failed");
    }


    function functionDelegateCall(
        address target,
        bytes memory data,
        string memory errorMessage
    ) internal returns (bytes memory) {
        require(isContract(target), "Address: delegate call to non-contract");

        (bool success, bytes memory returndata) = target.delegatecall(data);
        return _verifyCallResult(success, returndata, errorMessage);
    }

    function _verifyCallResult(
        bool success,
        bytes memory returndata,
        string memory errorMessage
    ) private pure returns (bytes memory) {
        if (success) {
            return returndata;
        } else {

            if (returndata.length > 0) {


                assembly {
                    let returndata_size := mload(returndata)
                    revert(add(32, returndata), returndata_size)
                }
            } else {
                revert(errorMessage);
            }
        }
    }
}


library SafeERC20 {
    using Address for address;

    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transfer.selector, to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        _callOptionalReturn(token, abi.encodeWithSelector(token.transferFrom.selector, from, to, value));
    }


    function safeApprove(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {



        require(
            (value == 0) || (token.allowance(address(this), spender) == 0),
            "SafeERC20: approve from non-zero to non-zero allowance"
        );
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, value));
    }

    function safeIncreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        uint256 newAllowance = token.allowance(address(this), spender) + value;
        _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
    }

    function safeDecreaseAllowance(
        IERC20 token,
        address spender,
        uint256 value
    ) internal {
        unchecked {
            uint256 oldAllowance = token.allowance(address(this), spender);
            require(oldAllowance >= value, "SafeERC20: decreased allowance below zero");
            uint256 newAllowance = oldAllowance - value;
            _callOptionalReturn(token, abi.encodeWithSelector(token.approve.selector, spender, newAllowance));
        }
    }


    function _callOptionalReturn(IERC20 token, bytes memory data) private {




        bytes memory returndata = address(token).functionCall(data, "SafeERC20: low-level call failed");
        if (returndata.length > 0) {

            require(abi.decode(returndata, (bool)), "SafeERC20: ERC20 operation did not succeed");
        }
    }
}

interface ILendingPool {
  function deposit(address asset, uint256 amount, address onBehalfOf, uint16 referralCode) external;
  function withdraw(address asset, uint256 amount, address to) external returns (uint256);
}

interface IAaveIncentivesController {
    function getRewardsBalance(address[] memory assets, address user) external view returns (uint256);
    function claimRewards(address[] memory assets, uint256 amount, address to) external;
}

interface IWUSDMaster {
    function treasury() external view returns (address);
}

contract WusdAaveStrategy is Ownable {
    using SafeERC20 for IERC20;


    IERC20 public immutable usdc = IERC20(0x2791Bca1f2de4661ED88A30C99A7a9449Aa84174);
    IERC20 public immutable wmatic = IERC20(0x0d500B1d8E8eF31E21C99d1Db9A6444d3ADf1270);
    IERC20 public immutable amUsdc = IERC20(0x1a13F4Ca1d028320A707D99520AbFefca3998b7F);
    ILendingPool public immutable lendingPool = ILendingPool(0x8dFf5E27EA6b7AC08EbFdf9eB090F32ee9a30fcf);
    IAaveIncentivesController public immutable rewardsContract = IAaveIncentivesController(0x357D51124f59836DeD84c8a1730D72B749d8BC23);
    IWUSDMaster public immutable wusdMaster = IWUSDMaster(0xc9fF58Bd2A1CB4FAB0fEC5A0D061527Db1fbb923);

    uint256 public usdcInvestedAmount = 0;

    event UsdcInvested(uint256 amount);
    event UsdcWithdrawnToTreasury(uint256 amount);
    event UsdcWithdrawnToMaster(uint256 amount);


    function treasury() public view returns (address) {
        return wusdMaster.treasury();
    }

    function wmaticRewardsAmount() external view returns (uint256) {
        address[] memory assets = new address[](1);
        assets[0] = address(amUsdc);
        return rewardsContract.getRewardsBalance(assets, address(this));
    }

    function expectedTotalUsdcAmount() external view returns (uint256) {
        return amUsdc.balanceOf(address(this));
    }

    function expectedUsdcRewards() external view returns (uint256) {
        return amUsdc.balanceOf(address(this)) - usdcInvestedAmount;
    }

    function investAll() external {
        uint256 usdcBalance = usdc.balanceOf(address(this));
        invest(usdcBalance);
    }

    function invest(uint256 usdcAmount) public onlyOwner {
        uint256 usdcBalance = usdc.balanceOf(address(this));
        require(usdcBalance >= usdcAmount, 'not enough USDC in strategy');

        usdc.approve(address(lendingPool), usdcAmount);
        lendingPool.deposit(address(usdc), usdcAmount, address(this), 0);
        usdcInvestedAmount += usdcAmount;

        emit UsdcInvested(usdcAmount);
    }

    function withdraw(address to, uint256 amUsdcAmount) internal returns (uint256) {
        return lendingPool.withdraw(address(usdc), amUsdcAmount, to);
    }

    function withdrawToMaster(uint256 amUsdcAmount) external onlyOwner {
        uint256 amUsdcBalance = amUsdc.balanceOf(address(this));
        require(amUsdcAmount <= amUsdcBalance, 'not enough amUSDC');
        require(amUsdcAmount <= usdcInvestedAmount, 'withdrawing more than invested');

        uint256 usdcWithdrawn = withdraw(address(wusdMaster), amUsdcAmount);
        usdcInvestedAmount -= usdcWithdrawn;

        emit UsdcWithdrawnToTreasury(usdcWithdrawn);
    }

    function withdrawUsdcRewards(uint256 amUsdcAmount) external onlyOwner {
        uint256 amUsdcBalance = amUsdc.balanceOf(address(this));
        require(amUsdcAmount <= amUsdcBalance, 'not enough amUSDC');
        require(amUsdcBalance - amUsdcAmount >= usdcInvestedAmount, 'withdrawing more than rewards');

        uint256 usdcWithdrawn = withdraw(treasury(), amUsdcAmount);

        emit UsdcWithdrawnToTreasury(usdcWithdrawn);
    }

    function claimWMaticRewards(uint256 wmaticAmount) external onlyOwner {
        address[] memory assets = new address[](1);
        assets[0] = address(amUsdc);
        rewardsContract.claimRewards(assets, wmaticAmount, address(this));
        uint256 wmaticBalance = wmatic.balanceOf(address(this));
        wmatic.safeTransfer(treasury(), wmaticBalance);
    } 

    function withdrawAll() external onlyOwner {
        uint256 amUsdcBalance = amUsdc.balanceOf(address(this));
        uint256 usdcWithdrawn = lendingPool.withdraw(address(usdc), amUsdcBalance, address(this));
        if(usdcWithdrawn > usdcInvestedAmount) {
            usdc.safeTransfer(treasury(), usdcWithdrawn - usdcInvestedAmount);
            usdc.safeTransfer(address(wusdMaster), usdcInvestedAmount);

            emit UsdcWithdrawnToTreasury(usdcWithdrawn - usdcInvestedAmount);
            emit UsdcWithdrawnToMaster(usdcInvestedAmount);
        } else {
            usdc.safeTransfer(address(wusdMaster), usdcWithdrawn);

            emit UsdcWithdrawnToMaster(usdcWithdrawn);
        }
        usdcInvestedAmount = 0;
    }

    function returnUsdcToMaster() external onlyOwner {
        uint256 amount = usdc.balanceOf(address(this));
        usdc.safeTransfer(address(wusdMaster), amount);

        emit UsdcWithdrawnToMaster(amount);
    }

}

